- 'blossomed into maturity' refers to age > 18;
- 'classes' refer to the passenger's ticket class (1st, 2nd, or 3rd);
- 'embarked' refers to the total number of passengers in each group;
- 'survived' refers to the number of passengers who survived in each group.

sql:
SELECT AVG(fare) AS average_fare
FROM passengers
WHERE pclass = 1 AND travel_insurance = 1 AND embarked = 'Southampton';

SELECT nationality, AVG(survival_rate) AS average_survival_rate
FROM survival_statistics
GROUP BY nationality;

